// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./HubDappIntegrable.sol";

contract HubDappExample is HubDappIntegrable {
    using SafeERC20 for IERC20;

    address public revenueToken;
    mapping(address => uint256) public netRevenue;

    event RevenueProcessed(
        address indexed payer,
        uint256 grossAmount,
        uint256 netAmount,
        address indexed token,
        uint256 targetChainId,
        bytes32 category
    );

    constructor(
        address _revenueToken,
        address _hubFeeCollector,
        uint16 _hubFeeBps
    ) {
        require(_revenueToken != address(0), "Invalid revenue token");
        require(_hubFeeCollector != address(0), "Invalid fee collector");
        require(_hubFeeBps <= 2000, "Fee too high");

        revenueToken = _revenueToken;
        hubFeeCollector = _hubFeeCollector;
        hubFeeBps = _hubFeeBps;
    }

    function setRevenueToken(address token) external onlyOwner {
        require(token != address(0), "Invalid token");
        revenueToken = token;
    }

    function processRevenue(
        uint256 grossAmount,
        uint256 targetChainId,
        bytes32 category
    ) external returns (uint256 netAmount) {
        netAmount = _collectHubFee(revenueToken, grossAmount, targetChainId, category);
        netRevenue[msg.sender] += netAmount;
        emit RevenueProcessed(msg.sender, grossAmount, netAmount, revenueToken, targetChainId, category);
    }

    function withdrawNetRevenue(address token, uint256 amount) external {
        require(netRevenue[msg.sender] >= amount, "Insufficient net revenue");
        netRevenue[msg.sender] -= amount;
        IERC20(token).safeTransfer(msg.sender, amount);
    }
}

contracts/hub/HubDappIntegrable.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

interface IHubFeeCollector {
    function collectHubFee(
        address payer,
        address token,
        uint256 amount,
        uint256 targetChainId,
        bytes32 category,
        bytes calldata data
    ) external payable;
}

abstract contract HubDappIntegrable is Ownable {
    using SafeERC20 for IERC20;

    address public hubFeeCollector;
    uint16 public hubFeeBps;

    event HubFeeConfig(address indexed collector, uint16 feeBps);
    event DappAudit(address indexed payer, uint256 grossAmount, uint256 netAmount, uint256 feeAmount, uint256 timestamp);

    function setHubFeeConfig(address collector, uint16 feeBps) external onlyOwner {
        require(collector != address(0), "Invalid collector");
        require(feeBps <= 2000, "Fee too high");
        hubFeeCollector = collector;
        hubFeeBps = feeBps;
        emit HubFeeConfig(collector, feeBps);
    }

    function _collectHubFee(
        address token,
        uint256 grossAmount,
        uint256 targetChainId,
        bytes32 category
    ) internal returns (uint256) {
        require(hubFeeCollector != address(0), "Fee collector not set");
        require(hubFeeBps > 0, "Fee bps not configured");
        require(grossAmount > 0, "Gross amount zero");

        uint256 fee = (grossAmount * hubFeeBps) / 10000;
        uint256 netAmount = grossAmount - fee;

        if (token == address(0)) {
            require(msg.value == grossAmount, "Invalid native amount");
            IHubFeeCollector(hubFeeCollector).collectHubFee{value: fee}(
                msg.sender,
                token,
                fee,
                targetChainId,
                category,
                ""
            );
        } else {
            IERC20(token).safeTransferFrom(msg.sender, address(this), grossAmount);
            require(IERC20(token).balanceOf(address(this)) >= grossAmount, "Dapp did not receive gross");
            IERC20(token).safeTransfer(hubFeeCollector, fee);
            require(IERC20(token).balanceOf(hubFeeCollector) >= fee, "Fee collector not funded");
            IHubFeeCollector(hubFeeCollector).collectHubFee(
                msg.sender,
                token,
                fee,
                targetChainId,
                category,
                ""
            );
            emit DappAudit(msg.sender, grossAmount, netAmount, fee, block.timestamp);
        }

        return netAmount;
    }
}

contracts/hub/HubFeeCollector.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./HubFeeRouter.sol";

interface IHubFeeCollector {
    event HubFeeCollected(
        address indexed payer,
        address indexed token,
        uint256 amount,
        uint256 targetChainId,
        bytes32 category,
        bytes data
    );

    function collectHubFee(
        address payer,
        address token,
        uint256 amount,
        uint256 targetChainId,
        bytes32 category,
        bytes calldata data
    ) external payable;
}

contract HubFeeCollector is Ownable, IHubFeeCollector {
    using SafeERC20 for IERC20;

    address public feeRouter;

    constructor() {}

    event FeeRouterUpdated(address indexed router);
    event CollectorAudit(address indexed token, uint256 amount, address indexed destination, uint256 timestamp);

    modifier onlyFeeRouterSet() {
        require(feeRouter != address(0), "Fee router not set");
        _;
    }

    function setFeeRouter(address _feeRouter) external onlyOwner {
        require(_feeRouter != address(0), "Invalid router");
        feeRouter = _feeRouter;
        emit FeeRouterUpdated(_feeRouter);
    }

    function collectHubFee(
        address payer,
        address token,
        uint256 amount,
        uint256 targetChainId,
        bytes32 category,
        bytes calldata data
    ) external payable override onlyFeeRouterSet {
        if (token == address(0)) {
            require(msg.value == amount, "Invalid native amount");
            HubFeeRouter(feeRouter).routeFee{value: msg.value}(token, payer, amount, targetChainId, category);
        } else {
            uint256 currentBalance = IERC20(token).balanceOf(address(this));
            if (currentBalance < amount) {
                IERC20(token).safeTransferFrom(msg.sender, address(this), amount);
            }
            // Approve router to pull the fees
            IERC20(token).safeApprove(feeRouter, amount);
            HubFeeRouter(feeRouter).routeFee(token, payer, amount, targetChainId, category);
            emit CollectorAudit(token, amount, feeRouter, block.timestamp);
        }

        emit HubFeeCollected(payer, token, amount, targetChainId, category, data);
    }
}

contracts/hub/HubFeeRouter.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "../../adapters/UniversalAdapter.sol";
import "./HubTreasury.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

contract HubFeeRouter is Ownable {
    using SafeERC20 for IERC20;

    UniversalAdapter public adapter;
    uint256 public localChainId;
    address public feeCollector;

    mapping(uint256 => address) public treasuryByChain;

    event FeeCollectorUpdated(address indexed feeCollector);
    event TreasuryRegistered(uint256 indexed chainId, address indexed treasury);
    event FeeRouted(
        address indexed token,
        uint256 amount,
        uint256 localChainId,
        uint256 targetChainId,
        bytes32 category
    );
    event FeeAudit(
        address indexed payer,
        address indexed token,
        uint256 amount,
        address indexed treasury,
        uint256 timestamp
    );

    modifier onlyFeeCollector() {
        require(msg.sender == feeCollector, "Only fee collector");
        _;
    }

    constructor(address _adapter, uint256 _localChainId) {
        require(_adapter != address(0), "Invalid adapter");
        adapter = UniversalAdapter(_adapter);
        localChainId = _localChainId;
    }

    function setFeeCollector(address _feeCollector) external onlyOwner {
        require(_feeCollector != address(0), "Invalid collector");
        feeCollector = _feeCollector;
        emit FeeCollectorUpdated(_feeCollector);
    }

    function registerTreasury(uint256 chainId, address treasury) external onlyOwner {
        require(treasury != address(0), "Invalid treasury");
        treasuryByChain[chainId] = treasury;
        emit TreasuryRegistered(chainId, treasury);
    }

    function routeFee(
        address token,
        address payer,
        uint256 amount,
        uint256 targetChainId,
        bytes32 category
    ) external payable onlyFeeCollector {
        address payable treasury = payable(treasuryByChain[targetChainId]);
        require(treasury != address(0), "Treasury not registered");
        require(amount > 0, "Zero amount");

        if (targetChainId == localChainId) {
            if (token == address(0)) {
                require(msg.value == amount, "Invalid amount");
                HubTreasury(treasury).collectFee{value: amount}(token, payer, amount, category);
            } else {
                // Pull from collector and transfer to treasury
                IERC20(token).safeTransferFrom(msg.sender, treasury, amount);
                HubTreasury(treasury).collectFee(token, payer, amount, category);
                emit FeeAudit(payer, token, amount, treasury, block.timestamp);
            }
        } else {
            require(token != address(0), "Cross-chain native not supported");
            adapter.withdraw(token, msg.sender, amount, localChainId);
            adapter.deposit(token, treasury, amount, targetChainId);
        }

        emit FeeRouted(token, amount, localChainId, targetChainId, category);
    }
}

contracts/hub/HubGovernance.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

interface IHubStaking {
    function stakePower(address account) external view returns (uint256);
}

contract HubGovernance is Ownable {
    IERC20 public x3;
    IERC20 public wrappedX3;
    IERC20 public hubToken;
    IHubStaking public hubStaking;

    uint256 public constant TIMELOCK_DELAY = 2 days;

    struct Proposal {
        string description;
        uint256 voteStart;
        uint256 voteEnd;
        uint256 forVotes;
        uint256 againstVotes;
        bool executed;
        uint256 executionTime;
        mapping(address => bool) voted;
    }

    uint256 public proposalCount;
    mapping(uint256 => Proposal) private proposals;

    event ProposalCreated(uint256 indexed id, string description, uint256 voteStart, uint256 voteEnd);
    event Voted(uint256 indexed id, address indexed voter, bool support, uint256 weight);
    event ProposalExecuted(uint256 indexed id, bool approved, uint256 executedAt);
    event ProposalQueued(uint256 indexed id, uint256 executionTime);
    event GovernanceAudit(uint256 indexed proposalId, uint256 forVotes, uint256 againstVotes, bool passed, uint256 timestamp);

    constructor(
        address _x3,
        address _wrappedX3,
        address _hubToken,
        address _hubStaking
    ) {
        require(_x3 != address(0), "Invalid x3");
        require(_wrappedX3 != address(0), "Invalid wrappedX3");
        require(_hubToken != address(0), "Invalid hubToken");
        require(_hubStaking != address(0), "Invalid staking");

        x3 = IERC20(_x3);
        wrappedX3 = IERC20(_wrappedX3);
        hubToken = IERC20(_hubToken);
        hubStaking = IHubStaking(_hubStaking);
    }

    function createProposal(string calldata description, uint256 duration) external onlyOwner {
        require(duration > 0, "Duration required");

        proposalCount += 1;
        Proposal storage proposal = proposals[proposalCount];
        proposal.description = description;
        proposal.voteStart = block.number;
        proposal.voteEnd = block.number + duration;

        emit ProposalCreated(proposalCount, description, proposal.voteStart, proposal.voteEnd);
    }

    function vote(uint256 id, bool support) external {
        Proposal storage proposal = proposals[id];
        require(block.number >= proposal.voteStart, "Voting not started");
        require(block.number <= proposal.voteEnd, "Voting ended");
        require(!proposal.voted[msg.sender], "Already voted");

        uint256 weight = votingPower(msg.sender);
        require(weight > 0, "No voting power");

        proposal.voted[msg.sender] = true;
        if (support) {
            proposal.forVotes += weight;
        } else {
            proposal.againstVotes += weight;
        }

        emit Voted(id, msg.sender, support, weight);
    }

    function queueProposal(uint256 id) external onlyOwner {
        Proposal storage proposal = proposals[id];
        require(block.number > proposal.voteEnd, "Voting not finished");
        require(proposal.executionTime == 0, "Already queued");

        proposal.executionTime = block.timestamp + TIMELOCK_DELAY;
        emit ProposalQueued(id, proposal.executionTime);
    }

    function execute(uint256 id) external onlyOwner {
        Proposal storage proposal = proposals[id];
        require(proposal.executionTime > 0, "Proposal not queued");
        require(block.timestamp >= proposal.executionTime, "Timelock not expired");
        require(!proposal.executed, "Already executed");

        proposal.executed = true;
        bool approved = proposal.forVotes > proposal.againstVotes;
        emit ProposalExecuted(id, approved, block.timestamp);
        emit GovernanceAudit(id, proposal.forVotes, proposal.againstVotes, approved, block.timestamp);
    }

    function votingPower(address voter) public view returns (uint256) {
        return x3.balanceOf(voter)
            + wrappedX3.balanceOf(voter)
            + hubToken.balanceOf(voter)
            + hubStaking.stakePower(voter);
    }

    function getProposal(uint256 id)
        external
        view
        returns (
            string memory description,
            uint256 voteStart,
            uint256 voteEnd,
            uint256 forVotes,
            uint256 againstVotes,
            bool executed
        )
    {
        Proposal storage proposal = proposals[id];
        return (
            proposal.description,
            proposal.voteStart,
            proposal.voteEnd,
            proposal.forVotes,
            proposal.againstVotes,
            proposal.executed
        );
    }
}

contracts/hub/HubGovToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract HubGovToken is ERC20, Ownable {
    uint256 public immutable maxSupply;

    constructor(string memory name, string memory symbol, uint256 _maxSupply) ERC20(name, symbol) {
        maxSupply = _maxSupply;
    }

    event Minted(address indexed to, uint256 amount);
    event Burned(address indexed from, uint256 amount);

    function mint(address to, uint256 amount) external onlyOwner {
        if (maxSupply > 0) {
            require(totalSupply() + amount <= maxSupply, "Max supply exceeded");
        }
        _mint(to, amount);
        emit Minted(to, amount);
    }

    function burn(address from, uint256 amount) external onlyOwner {
        _burn(from, amount);
        emit Burned(from, amount);
    }
}

contracts/hub/HubStakingPool.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

contract HubStakingPool is Ownable {
    using SafeERC20 for IERC20;

    IERC20 public stakingToken;
    IERC20 public rewardToken;
    uint256 public rewardRate;
    uint256 public totalStaked;
    uint256 public lastUpdateBlock;
    uint256 public accRewardPerShare;

    mapping(address => uint256) public stakeAmount;
    mapping(address => uint256) public rewardDebt;

    event RewardRateUpdated(uint256 rewardRate);
    event Staked(address indexed user, uint256 amount);
    event Unstaked(address indexed user, uint256 amount);
    event Claimed(address indexed user, uint256 amount);

    constructor(address _stakingToken, address _rewardToken, uint256 _rewardRate) {
        require(_stakingToken != address(0), "Invalid staking token");
        require(_rewardToken != address(0), "Invalid reward token");

        stakingToken = IERC20(_stakingToken);
        rewardToken = IERC20(_rewardToken);
        rewardRate = _rewardRate;
        lastUpdateBlock = block.number;
    }

    function setRewardRate(uint256 _rewardRate) external onlyOwner {
        updatePool();
        rewardRate = _rewardRate;
        emit RewardRateUpdated(_rewardRate);
    }

    function updatePool() public {
        if (totalStaked == 0) {
            lastUpdateBlock = block.number;
            return;
        }

        uint256 blocks = block.number - lastUpdateBlock;
        accRewardPerShare += (blocks * rewardRate * 1e12) / totalStaked;
        lastUpdateBlock = block.number;
    }

    function pendingReward(address user) public view returns (uint256) {
        uint256 currentAcc = accRewardPerShare;
        if (totalStaked != 0) {
            uint256 blocks = block.number - lastUpdateBlock;
            currentAcc += (blocks * rewardRate * 1e12) / totalStaked;
        }
        return (stakeAmount[user] * currentAcc) / 1e12 - rewardDebt[user];
    }

    function stake(uint256 amount) external {
        require(amount > 0, "Zero stake");
        updatePool();

        stakingToken.safeTransferFrom(msg.sender, address(this), amount);
        stakeAmount[msg.sender] += amount;
        totalStaked += amount;
        rewardDebt[msg.sender] = (stakeAmount[msg.sender] * accRewardPerShare) / 1e12;

        emit Staked(msg.sender, amount);
    }

    function claim() external {
        updatePool();
        uint256 pending = pendingReward(msg.sender);
        require(pending > 0, "No rewards");

        rewardDebt[msg.sender] = (stakeAmount[msg.sender] * accRewardPerShare) / 1e12;
        rewardToken.safeTransfer(msg.sender, pending);

        emit Claimed(msg.sender, pending);
    }

    function unstake(uint256 amount) external {
        require(amount > 0, "Zero unstake");
        require(stakeAmount[msg.sender] >= amount, "Insufficient stake");

        updatePool();
        uint256 pending = pendingReward(msg.sender);
        stakeAmount[msg.sender] -= amount;
        totalStaked -= amount;
        rewardDebt[msg.sender] = (stakeAmount[msg.sender] * accRewardPerShare) / 1e12;

        stakingToken.safeTransfer(msg.sender, amount);
        if (pending > 0) {
            rewardToken.safeTransfer(msg.sender, pending);
        }

        emit Unstaked(msg.sender, amount);
        if (pending > 0) {
            emit Claimed(msg.sender, pending);
        }
    }

    function stakePower(address account) external view returns (uint256) {
        return stakeAmount[account];
    }
}

