// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

contract HubTreasury is Ownable {
    using SafeERC20 for IERC20;

    address public devWallet;
    address public daoWallet;
    address public reserveWallet;
    address public feeRouter;

    constructor(
        address _devWallet,
        address _daoWallet,
        address _reserveWallet,
        address _feeRouter
    ) {
        require(_devWallet != address(0), "Invalid dev wallet");
        require(_daoWallet != address(0), "Invalid dao wallet");
        require(_reserveWallet != address(0), "Invalid reserve wallet");

        devWallet = _devWallet;
        daoWallet = _daoWallet;
        reserveWallet = _reserveWallet;
        feeRouter = _feeRouter;

        devBps = 1500;
        daoBps = 5000;
        reserveBps = 3500;
    }

    uint16 public devBps;
    uint16 public daoBps;
    uint16 public reserveBps;

    event FeeRouterUpdated(address indexed feeRouter);
    event FeeSplitsUpdated(uint16 devBps, uint16 daoBps, uint16 reserveBps);
    event FeeReceived(address indexed source, address indexed token, uint256 amount, bytes32 category);

    modifier onlyRouter() {
        require(msg.sender == feeRouter, "Only router");
        _;
    }

    function setFeeRouter(address _feeRouter) external onlyOwner {
        require(_feeRouter != address(0), "Invalid router");
        feeRouter = _feeRouter;
        emit FeeRouterUpdated(_feeRouter);
    }

    function setFeeSplits(uint16 _devBps, uint16 _daoBps, uint16 _reserveBps) external onlyOwner {
        require(_devBps + _daoBps + _reserveBps == 10000, "Split must equal 10000");
        devBps = _devBps;
        daoBps = _daoBps;
        reserveBps = _reserveBps;
        emit FeeSplitsUpdated(_devBps, _daoBps, _reserveBps);
    }

    function collectFee(
        address token,
        address source,
        uint256 amount,
        bytes32 category
    ) external payable onlyRouter {
        require(amount > 0, "Zero amount");

        if (token == address(0)) {
            require(msg.value == amount, "Native mismatch");
            _routeNative(amount);
        } else {
            require(msg.value == 0, "Unexpected native");
            _routeERC20(token, amount);
        }

        emit FeeReceived(source, token, amount, category);
    }

    function sweepERC20(address token, uint256 amount, address recipient) external onlyOwner {
        require(recipient != address(0), "Invalid recipient");
        IERC20(token).safeTransfer(recipient, amount);
    }

    function sweepNative(uint256 amount, address payable recipient) external onlyOwner {
        require(recipient != address(0), "Invalid recipient");
        (bool success, ) = recipient.call{value: amount}("");
        require(success, "Native sweep failed");
    }

    receive() external payable {}

    function _routeERC20(address token, uint256 amount) internal {
        uint256 devAmount = (amount * devBps) / 10000;
        uint256 daoAmount = (amount * daoBps) / 10000;
        uint256 reserveAmount = amount - devAmount - daoAmount;

        IERC20(token).safeTransfer(devWallet, devAmount);
        IERC20(token).safeTransfer(daoWallet, daoAmount);
        IERC20(token).safeTransfer(reserveWallet, reserveAmount);
    }

    function _routeNative(uint256 amount) internal {
        uint256 devAmount = (amount * devBps) / 10000;
        uint256 daoAmount = (amount * daoBps) / 10000;
        uint256 reserveAmount = amount - devAmount - daoAmount;

        (bool successDev, ) = payable(devWallet).call{value: devAmount}("");
        require(successDev, "Dev transfer failed");

        (bool successDao, ) = payable(daoWallet).call{value: daoAmount}("");
        require(successDao, "DAO transfer failed");

        (bool successReserve, ) = payable(reserveWallet).call{value: reserveAmount}("");
        require(successReserve, "Reserve transfer failed");
    }
}

