// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

/**
 * X3 Flash Pool (UC1)
 * Minimal implementation for cross-chain arbitrage testing
 */

interface IERC20 {
    function balanceOf(address account) external view returns (uint256);
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(
        address from,
        address to,
        uint256 amount
    ) external returns (bool);
    function approve(address spender, uint256 amount) external returns (bool);
}

contract X3FlashPool {
    address public owner;
    mapping(address => uint256) public reserves;
    mapping(address => bool) public supportedTokens;

    event FlashLoanIssued(
        address indexed borrower,
        address indexed token,
        uint256 amount,
        uint256 fee
    );
    event FlashLoanRepaid(
        address indexed borrower,
        address indexed token,
        uint256 amount,
        uint256 fee
    );

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner");
        _;
    }

    function addToken(address token, uint256 initialReserve) public onlyOwner {
        require(token != address(0), "Invalid token");
        supportedTokens[token] = true;
        if (initialReserve > 0) {
            IERC20(token).transferFrom(msg.sender, address(this), initialReserve);
            reserves[token] = initialReserve;
        }
    }

    function removeToken(address token) public onlyOwner {
        supportedTokens[token] = false;
    }

    function flashLoan(
        address token,
        uint256 amount,
        bytes calldata data
    ) public returns (bool) {
        require(supportedTokens[token], "Token not supported");
        require(reserves[token] >= amount, "Insufficient liquidity");

        uint256 fee = (amount * 5) / 10000; // 0.05% fee

        // Issue loan
        reserves[token] -= amount;
        IERC20(token).transfer(msg.sender, amount);

        emit FlashLoanIssued(msg.sender, token, amount, fee);

        // Call callback (simplified - no actual callback execution)
        // In real impl: invoke external contract callback

        // Require repayment
        uint256 repaymentAmount = amount + fee;
        require(
            IERC20(token).balanceOf(address(this)) >= reserves[token] + repaymentAmount,
            "Repayment failed"
        );

        reserves[token] += repaymentAmount;

        emit FlashLoanRepaid(msg.sender, token, amount, fee);
        return true;
    }

    function getReserve(address token) public view returns (uint256) {
        return reserves[token];
    }

    function deposit(address token, uint256 amount) public {
        require(supportedTokens[token], "Token not supported");
        IERC20(token).transferFrom(msg.sender, address(this), amount);
        reserves[token] += amount;
    }

    function withdraw(address token, uint256 amount) public onlyOwner {
        require(reserves[token] >= amount, "Insufficient reserve");
        reserves[token] -= amount;
        IERC20(token).transfer(msg.sender, amount);
    }
}

